repeat task.wait() until game:IsLoaded()

local HttpService = game:GetService('HttpService')
local TeleportService = game:GetService('TeleportService')
local Players = game:GetService('Players')
local STATE_FILE = %q
local SCRIPT_NAME = %q

local function readState()
    if not (readfile and isfile and isfile(STATE_FILE)) then
        return nil
    end
    local ok, raw = pcall(readfile, STATE_FILE)
    if not ok or not raw or raw == '' then
        return nil
    end
    ok, raw = pcall(function()
        return HttpService:JSONDecode(raw)
    end)
    return ok and raw or nil
end

local function loadFarm()
    task.wait(2)
    if readfile and isfile and isfile(SCRIPT_NAME) then
        local ok, src = pcall(readfile, SCRIPT_NAME)
        if ok and src and src ~= '' then
            if src:byte(1) == 0xEF and src:byte(2) == 0xBB and src:byte(3) == 0xBF then
                src = src:sub(4)
            end
            loadstring(src, SCRIPT_NAME)()
        end
    end
end

local saved = readState()
if saved and saved.Hiding == true then
    while os.time() < (saved.HideUntil or 0) do
        task.wait(1)
    end
    if saved.ReturnPlaceId and saved.ReturnJobId and game.JobId ~= saved.ReturnJobId then
        if readfile and isfile and isfile('GG2_WeatherRejoin.lua') then
            local ok, boot = pcall(readfile, 'GG2_WeatherRejoin.lua')
            local queue = queue_on_teleport or (syn and syn.queue_on_teleport)
            if ok and boot and boot ~= '' and queue then
                pcall(function()
                    queue(boot)
                end)
            end
        end
        for _ = 1, 25 do
            local ok = pcall(function()
                TeleportService:TeleportToPlaceInstance(saved.ReturnPlaceId, saved.ReturnJobId, Players.LocalPlayer)
            end)
            if ok then
                return
            end
            task.wait(2)
        end
        pcall(function()
            TeleportService:Teleport(saved.ReturnPlaceId, Players.LocalPlayer)
        end)
        task.wait(5)
    end
end

